VALUES
  ('aboriginal-a5729396-moex-00124', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於家事事件之保全程序及暫時處分程序，下列敘述何者錯誤？', '["已繫屬之家事非訟事件，僅得適用家事事件法關於暫時處分之規定，不適用民事訴訟法關於保全程 序之規定", "於依家事事件法第41條合併之家事訴訟與家事非訟事件程序中，法院認有必要時，得依家事事件 法關於暫時處分之規定，合併就此二事件命為適當之暫時處分", "法院依法所為之暫時處分，得命令或禁止關係人為一定行為、定暫時狀態或為其他適當之處置", "法院依家事事件法所為之暫時處分裁定，得免供擔保"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00125', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列家事事件，何者並非請求裁判前應先經法院調解之事件？', '["宣告終止收養關係事件", "扶養事件", "監護或輔助宣告事件", "繼承回復請求事件 乙、刑事訴訟法部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00126', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲住臺南市與住新北市之乙共同至臺中市竊取丙所有之汽車 1 輛，並於高雄市將該車出售予知情之 丁，下列敘述何者錯誤？', '["臺灣臺南地方法院對甲、乙所犯竊盜罪有管轄權", "臺灣臺中地方法院對丁所犯故買贓物罪有管轄權", "臺灣新北地方法院對丁所犯故買贓物罪有管轄權", "臺灣高雄地方法院對甲、乙所犯竊盜罪有管轄權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00127', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '有關刑事訴訟程序之相關概念，下列敘述何者錯誤？', '["法院雖無管轄權，如有急迫情形，應於其管轄區域內為必要之處分", "除法律另有規定外，地方法院於刑事案件有第一審管轄權", "訴訟程序會因法院無管轄權而完全無效", "法院因發見真實之必要時，得於管轄區域外行其職務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00128', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '法官於刑事案件中，有下列何者之情形時，無須依刑事訴訟法第17條之規定自行迴避？', '["法官現為被告之配偶", "法官為被害人", "被害人覺得法官很主觀", "曾參與前審裁判之法官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00129', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於選任辯護人之敘述，下列何者正確？', '["偵查中經檢察官許可者，亦得選任非律師擔任辯護人", "被告之法定代理人，得獨立為被告選任辯護人", "強制辯護案件，審判長指定辯護人後，被告不得自聘律師", "被告因身心障礙，致無法為完全之陳述，無辯護人在場，檢察官逕予偵訊，程序合法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00130', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於逮捕敘述，下列何者錯誤？', '["對於準現行犯，僅能由司法警察官逮捕", "現行犯，不問任何人均得逕行逮捕", "對於通緝犯，利害關係人得逕行逮捕", "檢察官對自行到場之被告，經訊問後認犯罪嫌疑重大，且有羈押原因及必要時，得予逮捕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
